}

// Module-level mutable product catalog — in production this would be a
// database connection. We keep it in memory here so the sync + cache
// revalidation cycle is visible without external infrastructure.
let products: Product[] = [
  {
    id: 1,
    sku: "LAP-001",
    name: "Laptop",
    price: 999,
    stock: 50,
    category: "Electronics",
    status: "active",
    lastSynced: null,
  },
  {
    id: 2,
    sku: "PHN-002",
    name: "Phone",
    price: 699,
    stock: 120,
    category: "Electronics",
    status: "active",
    lastSynced: null,
  },
  {
