  },
];

let syncInProgress = false;

/** Simulates database-read latency. */
function delay(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

/**
 * Returns the current product catalog.
 *
 * Called from the page via `unstable_cache` which stores the result under the
 * `"products"` cache tag.  The tag is invalidated by the sync action so that
 * subsequent renders see fresh data without a full redeploy.
 */
export async function getAllProducts(): Promise<Product[]> {
  await delay(80);
  return products.map((p) => ({ ...p }));
}

/**
 * Simulates an upstream ERP/PIM sync — pricing, inventory, and availability
 * updates that typically touch thousands of SKUs.
 *
 * Designed to be fired in the background: the caller triggers it without
 * awaiting, then immediately calls `revalidateTag("products")`.  The catalog
 * will be briefly stale until this function finishes writing its updates.
 */
export async function syncCatalog(): Promise<{
  synced: number;
  timestamp: string;
  durationMs: number;
}> {
  if (syncInProgress) {
    console.warn("Sync already in progress — skipping duplicate request");
    return { synced: 0, timestamp: "", durationMs: 0 };
  }

  syncInProgress = true;
  const startedAt = Date.now();

  try {
    // Simulate a long-running batch sync (in production: API calls, ETL, DB writes)
    await delay(4000);

    const now = new Date().toISOString();

    products = products.map((p) => ({
      ...p,
      price: Math.round(p.price * (1 + (Math.random() - 0.5) * 0.2)),
      stock: Math.max(0, p.stock + Math.floor((Math.random() - 0.3) * 20)),
      lastSynced: now,
      status: Math.random() > 0.92 ? "discontinued" : ("active" as const),
    }));

    return {
      synced: products.length,
      timestamp: now,
      durationMs: Date.now() - startedAt,
    };
  } finally {
    syncInProgress = false;
  }
}

import { revalidateTag, unstable_cache } from "next/cache";
import { getAllProducts, syncCatalog, type Product } from "@/lib/db";

// ── Cache layer ──────────────────────────────────────────────────────
// The result of getAllProducts is cached under the "products" tag.
// Every view that depends on catalog data uses this same tag so that a
// single revalidation freshens them all concurrently.
const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ["admin-products-list"],
  { tags: ["products"] },
);

// ── Inline Server Action ─────────────────────────────────────────────
// Co-located with the page so the sync trigger and its cache-invalidation
// logic are visible right next to the rendered output.
async function syncCatalogAction() {
  "use server";

  console.log("⏳ Sync triggered — background job dispatched");

  // Fire the long-running sync in the background WITHOUT awaiting it.
  // The admin gets immediate control back even though the product list
  // may reflect pre-sync data for a few more seconds.
  syncCatalog().catch((err: Error) => {
    console.error("Background catalog sync failed:", err);
  });

  // Mark every fetch / cache entry tagged "products" as stale.
  // The NEXT render of any consumer (this page, an API route, a different
  // page) will re-execute its data function and see whatever state the
  // data layer has at that moment — eventually consistent after the
  // background sync finishes writing.
  revalidateTag("products");
}

// ── Helpers ──────────────────────────────────────────────────────────

function statusBadge(status: Product["status"]) {
  const colors: Record<Product["status"], string> = {
    active: "#16a34a",
    inactive: "#ca8a04",
    discontinued: "#dc2626",
  };
  return (
    <span
      style={{
        display: "inline-block",
        padding: "2px 8px",
        borderRadius: "999px",
        fontSize: "0.75rem",
        fontWeight: 600,
        color: "#fff",
        backgroundColor: colors[status],
      }}
    >
      {status}
    </span>
  );
}

// ── Page ─────────────────────────────────────────────────────────────

export default async function ProductsPage() {
  const products: Product[] = await getCachedProducts();

  const anySynced = products.some((p) => p.lastSynced !== null);

  return (
    <div style={{ maxWidth: 960, margin: "0 auto", padding: "2rem 1rem" }}>
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: "1.5rem",
        }}
      >
        <div>
          <h1 style={{ margin: 0, fontSize: "1.5rem", fontWeight: 700 }}>
            Product Catalog
          </h1>
          <p style={{ margin: "0.25rem 0 0", color: "#666", fontSize: "0.875rem" }}>
            {products.length} products
            {anySynced && (
              <span>
                {" · "}
                last synced{" "}
                {new Date(
                  Math.max(
                    ...products
                      .map((p) => p.lastSynced)
                      .filter(Boolean) as string[],
                  ),
                ).toLocaleString()}
              </span>
            )}
            {!anySynced && <span> — sync pending</span>}
          </p>
        </div>

        {/* Regular HTML form → native Server Action submission.
            No client JavaScript required; works even before hydration. */}
        <form action={syncCatalogAction}>
          <button
            type="submit"
            style={{
              padding: "0.5rem 1.25rem",
              borderRadius: 6,
              border: "1px solid #d1d5db",
              background: "#f9fafb",
              fontSize: "0.875rem",
              fontWeight: 600,
              cursor: "pointer",
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </div>

      <div style={{ overflowX: "auto" }}>
        <table
          style={{
            width: "100%",
            borderCollapse: "collapse",
            fontSize: "0.875rem",
          }}
        >
          <thead>
            <tr style={{ borderBottom: "2px solid #e5e7eb", textAlign: "left" }}>
              <th style={{ padding: "0.75rem 0.5rem" }}>SKU</th>
              <th style={{ padding: "0.75rem 0.5rem" }}>Name</th>
              <th style={{ padding: "0.75rem 0.5rem", textAlign: "right" }}>
                Price
              </th>
              <th style={{ padding: "0.75rem 0.5rem", textAlign: "right" }}>
                Stock
              </th>
              <th style={{ padding: "0.75rem 0.5rem" }}>Category</th>
              <th style={{ padding: "0.75rem 0.5rem" }}>Status</th>
              <th style={{ padding: "0.75rem 0.5rem" }}>Last synced</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr
                key={product.id}
                style={{ borderBottom: "1px solid #e5e7eb" }}
              >
                <td style={{ padding: "0.75rem 0.5rem", fontFamily: "monospace", fontSize: "0.8rem" }}>
                  {product.sku}
                </td>
                <td style={{ padding: "0.75rem 0.5rem", fontWeight: 500 }}>
                  {product.name}
                </td>
                <td style={{ padding: "0.75rem 0.5rem", textAlign: "right", fontVariantNumeric: "tabular-nums" }}>
                  ${product.price.toLocaleString()}
                </td>
                <td style={{ padding: "0.75rem 0.5rem", textAlign: "right", fontVariantNumeric: "tabular-nums" }}>
                  {product.stock}
                </td>
                <td style={{ padding: "0.75rem 0.5rem" }}>{product.category}</td>
                <td style={{ padding: "0.75rem 0.5rem" }}>
